101→pub async fn get_projects(
102→    AuthenticatedUser(user_id): AuthenticatedUser,
103→    State(pool): State<PgPool>,
104→) -> Result<Response, ProjectError> {
105→    let inbox_count = inbox_service::get_inbox_count(&pool, &user_id)
106→        .await
107→        .map_err(ProjectError::Unexpected)?;
108→
109→    let projects = project_service::list_active_projects(&pool, &user_id)
110→        .await
111→        .map_err(ProjectError::Unexpected)?;
112→
113→    let mut project_views = Vec::new();
114→    for project in &projects {
115→        let count = crate::infrastructure::project_repository::count_project_next_actions(
116→            &pool,
117→            project.id(),
118→        )
119→        .await
120→        .map_err(|e| ProjectError::Unexpected(anyhow::anyhow!("Database error: {e}")))?;
121→        project_views.push(build_project_view(project, count));
122→    }
123→
124→    let template = ProjectsTemplate {
125→        current_page: "projects",
126→        inbox_count,
127→        projects: project_views,
128→        error_message: None,
129→    };
130→    Ok(Html(template.render()?).into_response())
131→}
